using System;
using System.Diagnostics;
using System.Linq;
using GR.Memory;
using Microsoft.VisualStudio.TestTools.UnitTesting;



namespace TestProject
{
  [TestClass]
  public class TestMediaTool
  {
    [TestMethod]
    [DataRow( new string[] { "-GRAPHICSCREEN", "input", "-export", "output", "-TYPE", "HIRESBITMAP" }, "hires.graphicscreen", "", true )]
    [DataRow( new string[] { "-GRAPHICSCREEN", "input", "-export", "output", "-TYPE", "HIRESSCREEN" }, "hires.graphicscreen", "", true )]
    [DataRow( new string[] { "-GRAPHICSCREEN", "input", "-export", "output", "-TYPE", "HIRESCOLOR" }, "hires.graphicscreen", "", true )]
    [DataRow( new string[] { "-GRAPHICSCREEN", "input", "-export", "output", "-TYPE", "HIRESBITMAP", "-AREA", "256,48,24,24" }, "hires.graphicscreen", "fffef8e1c78f1f3ea000007effc01e7f3f07611cc6f3399c6c59dbb336367676c79f387067cfcfefcceee67636bcbd7976737b797c3e3f9f67713c9fc7701cc0f3c61dfffc411fff", true )]
    [DataRow( new string[] { "-GRAPHICSCREEN", "input", "-export", "output", "-TYPE", "HIRESSCREEN", "-AREA", "256,48,24,24" }, "hires.graphicscreen", "0a0a0a0a070a040a04", true )]
    [DataRow( new string[] { "-GRAPHICSCREEN", "input", "-export", "output", "-TYPE", "HIRESCOLOR", "-AREA", "256,48,24,24" }, "hires.graphicscreen", "000000000000000000", true )]
    [DataRow( new string[] { "-GRAPHICSCREEN", "input", "-export", "output", "-TYPE", "HIRESBITMAPSCREENCOLOR", "-AREA", "256,48,24,24" }, "hires.graphicscreen", "fffef8e1c78f1f3ea000007effc01e7f3f07611cc6f3399c6c59dbb336367676c79f387067cfcfefcceee67636bcbd7976737b797c3e3f9f67713c9fc7701cc0f3c61dfffc411fff0a0a0a0a070a040a04000000000000000000", true )]
    [DataRow( new string[] { "-GRAPHICSCREEN", "input", "-export", "output", "-TYPE", "HIRESBITMAPCOLORSCREEN", "-AREA", "256,48,24,24" }, "hires.graphicscreen", "fffef8e1c78f1f3ea000007effc01e7f3f07611cc6f3399c6c59dbb336367676c79f387067cfcfefcceee67636bcbd7976737b797c3e3f9f67713c9fc7701cc0f3c61dfffc411fff0000000000000000000a0a0a0a070a040a04", true )]
    [DataRow( new string[] { "-GRAPHICSCREEN", "input", "-export", "output", "-TYPE", "HIRESSCREENCOLOR", "-AREA", "256,48,24,24" }, "hires.graphicscreen", "0a0a0a0a070a040a04000000000000000000", true )]
    [DataRow( new string[] { "-GRAPHICSCREEN", "input", "-export", "output", "-TYPE", "HIRESCOLORSCREEN", "-AREA", "256,48,24,24" }, "hires.graphicscreen", "0000000000000000000a0a0a0a070a040a04", true )]
    [DataRow( new string[] { "-GRAPHICSCREEN", "input", "-export", "output", "-TYPE", "HIRESCOLORBITMAP", "-AREA", "256,48,24,24" }, "hires.graphicscreen", "000000000000000000fffef8e1c78f1f3ea000007effc01e7f3f07611cc6f3399c6c59dbb336367676c79f387067cfcfefcceee67636bcbd7976737b797c3e3f9f67713c9fc7701cc0f3c61dfffc411fff", true )]
    [DataRow( new string[] { "-GRAPHICSCREEN", "input", "-export", "output", "-TYPE", "HIRESSCREENBITMAP", "-AREA", "256,48,24,24" }, "hires.graphicscreen", "0a0a0a0a070a040a04fffef8e1c78f1f3ea000007effc01e7f3f07611cc6f3399c6c59dbb336367676c79f387067cfcfefcceee67636bcbd7976737b797c3e3f9f67713c9fc7701cc0f3c61dfffc411fff", true )]
    public void TestMediaToolExportHiresBitmap( string[] args, string inputFile, string expectedOutputFileContentHex, bool expectedSuccess )
    {
      var tool = new MediaTool.Manager();

      string baseDir = AppContext.BaseDirectory;
      args[1] = System.IO.Path.Combine( baseDir, "TestData", inputFile );
      args[3] = System.IO.Path.Combine( baseDir, "TestData", "output.dat" );

      int result = tool.Handle( args );

      Assert.AreEqual( expectedSuccess ? 0 : 1, result );

      if ( result == 0 )
      {
        var outputData = GR.IO.File.ReadAllBytes( args[3] );
        var expectedData = new ByteBuffer( expectedOutputFileContentHex );
        Assert.AreEqual( expectedData.Length, outputData.Length, $"Data length mismatch" );
        for ( int i = 0; i < expectedData.Length; ++i )
        {
          Assert.AreEqual( expectedData[i], outputData[i], $"Data mismatch at position {i}" );
        }
      }
    }



    [TestMethod]
    [DataRow( new string[] { "-GRAPHICSCREEN", "input", "-export", "output", "-TYPE", "MULTICOLORBITMAP" }, "mc.graphicscreen", "", true )]
    [DataRow( new string[] { "-GRAPHICSCREEN", "input", "-export", "output", "-TYPE", "MULTICOLORBITMAP", "-AREA", "168,72,32,32" }, "mc.graphicscreen", "55555555555555555656565656565655aaaaaaaaaaaaaa55aaaaaaaaaaaaaa55555555555555555555555555555656565555555555aaaaaa5555555555aaaaaa55555555555555555656565656565656555555555555555555555555555555555555555555555555565656565656565655555555555555555555555555555555", true )]
    [DataRow( new string[] { "-GRAPHICSCREEN", "input", "-export", "output", "-TYPE", "MULTICOLORCOLOR" }, "mc.graphicscreen", "", true )]
    [DataRow( new string[] { "-GRAPHICSCREEN", "input", "-export", "output", "-TYPE", "MULTICOLORCOLOR", "-AREA", "168,72,32,32" }, "mc.graphicscreen", "00000000000000000000000000000000", true )]
    [DataRow( new string[] { "-GRAPHICSCREEN", "input", "-export", "output", "-TYPE", "MULTICOLORSCREEN" }, "mc.graphicscreen", "", true )]
    [DataRow( new string[] { "-GRAPHICSCREEN", "input", "-export", "output", "-TYPE", "MULTICOLORSCREEN", "-AREA", "168,72,32,32" }, "mc.graphicscreen", "101e1e1e101212121012202010122020", true )]
    [DataRow( new string[] { "-GRAPHICSCREEN", "input", "-export", "output", "-TYPE", "MULTICOLORBITMAPSCREEN", "-AREA", "168,72,32,32" }, "mc.graphicscreen", "55555555555555555656565656565655aaaaaaaaaaaaaa55aaaaaaaaaaaaaa55555555555555555555555555555656565555555555aaaaaa5555555555aaaaaa55555555555555555656565656565656555555555555555555555555555555555555555555555555565656565656565655555555555555555555555555555555101e1e1e101212121012202010122020", true )]
    public void TestMediaToolExportMCBitmap( string[] args, string inputFile, string expectedOutputFileContentHex, bool expectedSuccess )
    {
      var tool = new MediaTool.Manager();

